// Filter: only process emails that have a PDF attachment
const items = $input.all();
const results = [];

for (const item of items) {
  // Check subject for resume-related keywords
  const subject = (item.json.subject || '').toLowerCase();
  const keywords = ['resume', 'cv', 'application', 'apply'];
  const isRelevant = keywords.some(k => subject.includes(k));

  // Check for PDF attachment
  const hasPdf = Object.keys(item.binary || {}).some(key => {
    const mime = item.binary[key].mimeType || '';
    const name = (item.binary[key].fileName || '').toLowerCase();
    return mime === 'application/pdf' || name.endsWith('.pdf');
  });

  if (hasPdf) {
    // Find the first PDF attachment key
    const pdfKey = Object.keys(item.binary).find(key => {
      const mime = item.binary[key].mimeType || '';
      const name = (item.binary[key].fileName || '').toLowerCase();
      return mime === 'application/pdf' || name.endsWith('.pdf');
    });

    results.push({
      json: {
        ...item.json,
        _pdfBinaryKey: pdfKey,
        _fromEmail: item.json.from?.value?.[0]?.address || '',
        _subject: item.json.subject || ''
      },
      binary: item.binary
    });
  }
}

return results;

