const response = $input.first().json;
const content = response.choices[0].message.content;
let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  parsed = { name: 'Unknown', email: '', skills: [], summary: '' };
}

// Get metadata from previous steps
const pdfFileName = $('Filter PDF Attachments').first().binary?.[$('Filter PDF Attachments').first().json._pdfBinaryKey]?.fileName || 'resume.pdf';

return [{
  json: {
    name: parsed.name || 'Unknown',
    email: parsed.email || $('Filter PDF Attachments').first().json._fromEmail || '',
    phone: parsed.phone || null,
    skills: parsed.skills || [],
    summary: parsed.summary || '',
    resumeFileName: pdfFileName,
    source: 'gmail',
    status: 'applied'
  }
}];
